export interface Event {
  type: string;
  data: Record<string, unknown>;
  version: number;
}

interface Snapshot {
  state: Record<string, unknown>;
  version: number;
}

export class EventStore {
  private events: Event[] = [];
  private version = 0;
  private snapshots: Snapshot[] = [];

  append(event: Omit<Event, 'version'>): void {
    this.version++;
    this.events.push({ ...event, version: this.version });
  }

  createSnapshot(state: Record<string, unknown>): void {
    this.snapshots.push({ state, version: this.version });
  }

  getLatestSnapshot(): Snapshot | null {
    return this.snapshots.length > 0
      ? this.snapshots[this.snapshots.length - 1]
      : null;
  }

  replay(fromSnapshot = true): Event[] {
    if (fromSnapshot) {
      const snapshot = this.getLatestSnapshot();
      if (snapshot) {
        return this.events.filter(e => e.version > snapshot.version);
      }
    }
    return [...this.events];
  }
}
